    pub sender: oneshot::Sender<Result<serde_json::Value, moltis_protocol::ErrorShape>>,
    pub created_at: Instant,
}

// ── Discovered hook info ─────────────────────────────────────────────────────

/// Metadata about a discovered hook, exposed to the web UI.
