    /// `"project"` or `"user"`.
    pub source: String,
    pub source_path: String,
    pub eligible: bool,
    pub missing_os: bool,
    pub missing_bins: Vec<String>,
    pub missing_env: Vec<String>,
    pub enabled: bool,
    /// Raw HOOK.md content (frontmatter + body).
    pub body: String,
    /// Server-rendered HTML of the markdown body (after frontmatter).
    pub body_html: String,
