/// Initialise tracing and optionally attach a [`LogBroadcastLayer`] that
/// captures events into an in-memory ring buffer for the web UI.
fn init_telemetry(cli: &Cli, log_buffer: Option<LogBuffer>) {
    // Start with user-specified or default log level
    let base_filter =
        EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new(&cli.log_level));

    // Suppress noisy chromiumoxide logs:
    // - "WS Invalid message" warnings (Chrome sends CDP events the library doesn't recognize)
    // - "WS Connection error" errors (normal when idle connections are closed)
    // These are expected browser sandbox behavior, not actionable errors.
    let filter = if let Ok(directive) = "chromiumoxide=off".parse() {
        base_filter.add_directive(directive)
    } else {
        base_filter
    };

    if let Some(ref buffer) = log_buffer {
        let levels = EnabledLogLevels::from_max_level_hint(filter.max_level_hint());
        buffer.set_enabled_levels(levels);
    }

    let registry = tracing_subscriber::registry().with(filter);

    // Optionally attach the in-memory capture layer.
    let log_layer = log_buffer.map(LogBroadcastLayer::new);

    if cli.json_logs {
        registry
            .with(fmt::layer().json().with_target(true).with_thread_ids(false))
            .with(log_layer)
            .init();
    } else {
        registry
            .with(
                fmt::layer()
                    .with_target(true)
                    .with_thread_ids(false)
                    .with_ansi(true),
            )
            .with(log_layer)
            .init();
    }
}

#[cfg(feature = "tls")]
async fn trust_ca() -> anyhow::Result<()> {
    let cert_dir = moltis_gateway::tls::cert_dir()?;
    let ca_path = cert_dir.join("ca.pem");

    if !ca_path.exists() {
        eprintln!(
            "CA certificate not found at {}. Start the gateway first to generate certificates.",
            ca_path.display()
        );
        return Ok(());
    }

    eprintln!("Installing CA certificate: {}", ca_path.display());

    #[cfg(target_os = "macos")]
    {
        let status = std::process::Command::new("security")
            .args([
                "add-trusted-cert",
                "-r",
                "trustRoot",
                "-k",
                &format!(
                    "{}/Library/Keychains/login.keychain-db",
                    std::env::var("HOME").unwrap_or_default()
                ),
            ])
            .arg(&ca_path)
            .status()?;
        if status.success() {
            eprintln!(
                "CA certificate installed successfully. Restart your browser to pick up the change."
            );
        } else {
            eprintln!("Failed to install CA certificate (exit code: {})", status);
        }
    }

    #[cfg(target_os = "linux")]
    {
        let dest = std::path::PathBuf::from("/usr/local/share/ca-certificates/moltis-ca.crt");
        eprintln!("Copying CA to {} (may require sudo)", dest.display());
        let status = std::process::Command::new("sudo")
            .args(["cp"])
            .arg(&ca_path)
            .arg(&dest)
            .status()?;
        if status.success() {
            let update = std::process::Command::new("sudo")
                .arg("update-ca-certificates")
                .status()?;
            if update.success() {
                eprintln!("CA certificate installed successfully.");
            } else {
                eprintln!("update-ca-certificates failed (exit code: {})", update);
            }
        } else {
            eprintln!("Failed to copy CA certificate (exit code: {})", status);
        }
    }

    #[cfg(not(any(target_os = "macos", target_os = "linux")))]
    {
        eprintln!(
            "Automatic trust installation is not supported on this OS.\n\
             Manually import the CA certificate from: {}",
            ca_path.display()
        );
    }

    Ok(())
}

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    dotenvy::dotenv().ok();
    let cli = Cli::parse();

    // Create the log buffer only for the gateway command so the web UI can
    // display captured log entries. Default capacity (1000) can be overridden
    // via `server.log_buffer_size` in moltis.toml.
    let log_buffer = if matches!(cli.command, None | Some(Commands::Gateway)) {
        Some(LogBuffer::default())
    } else {
        None
    };

    init_telemetry(&cli, log_buffer.clone());

    info!(version = env!("CARGO_PKG_VERSION"), "moltis starting");

    // Apply directory overrides before any command so all subcommands
    // (config check, db, sandbox, etc.) respect --config-dir / --data-dir.
    if let Some(ref dir) = cli.config_dir {
        moltis_config::set_config_dir(dir.clone());
    }
    if let Some(ref dir) = cli.data_dir {
        moltis_config::set_data_dir(dir.clone());
    }
    if let Some(ref dir) = cli.share_dir {
        moltis_config::set_share_dir(dir.clone());
    }

    // Ensure config/data directories exist for every command path. This is a
    // hard requirement for startup; fail fast if directory initialization fails.
    let config_dir =
        moltis_config::config_dir().ok_or_else(|| anyhow!("unable to resolve config directory"))?;
    std::fs::create_dir_all(&config_dir).unwrap_or_else(|e| {
        panic!(
            "failed to create config directory {}: {e}",
            config_dir.display()
        )
    });

    let data_dir = moltis_config::data_dir();
    std::fs::create_dir_all(&data_dir).unwrap_or_else(|e| {
        panic!(
            "failed to create data directory {}: {e}",
            data_dir.display()
        )
    });

    match cli.command {
        // Default: start gateway when no subcommand is provided
        None | Some(Commands::Gateway) => {
            // Load config to get server settings
            let config = moltis_config::discover_and_load();

            // CLI args override config values
            let bind = cli.bind.unwrap_or(config.server.bind);
            let port = cli.port.unwrap_or(config.server.port);

            #[cfg(feature = "tls")]
            let no_tls = cli.no_tls;
            #[cfg(not(feature = "tls"))]
            let no_tls = false;

            #[cfg(feature = "tailscale")]
            let tailscale_opts = cli
                .tailscale
                .map(|mode| moltis_gateway::server::TailscaleOpts {
                    mode,
                    reset_on_exit: cli.tailscale_reset_on_exit,
                });
            #[cfg(not(feature = "tailscale"))]
            let tailscale_opts: Option<()> = None;
            let _ = &tailscale_opts; // suppress unused warning when feature disabled
            #[cfg(feature = "web-ui")]
            let extra_routes: Option<moltis_gateway::server::RouteEnhancer> =
                Some(moltis_web::web_routes);
            #[cfg(not(feature = "web-ui"))]
            let extra_routes: Option<moltis_gateway::server::RouteEnhancer> = None;

            moltis_gateway::server::start_gateway(
                &bind,
                port,
                no_tls,
                log_buffer,
                cli.config_dir,
                cli.data_dir,
                #[cfg(feature = "tailscale")]
                tailscale_opts,
                extra_routes,
            )
            .await
        },
        Some(Commands::Agent { message, .. }) => {
            let result = moltis_agents::runner::run_agent("default", "main", &message).await?;
            println!("{result}");
            Ok(())
        },
        Some(Commands::Onboard) => {
            moltis_onboarding::wizard::run_onboarding().await?;
            Ok(())
        },
        Some(Commands::Channels { action }) => channel_commands::handle_channels(action).await,
        Some(Commands::Auth { action }) => auth_commands::handle_auth(action).await,
        Some(Commands::Sandbox { action }) => sandbox_commands::handle_sandbox(action).await,
        Some(Commands::Browser { action }) => browser_commands::handle_browser(action),
        Some(Commands::Db { action }) => db_commands::handle_db(action).await,
        Some(Commands::Memory { action }) => memory_commands::handle_memory(action).await,
        Some(Commands::Node { action }) => node_commands::handle_node(action).await,
        Some(Commands::Service { action }) => service_commands::handle_service(action),
        #[cfg(feature = "openclaw-import")]
        Some(Commands::Import { action }) => import_commands::handle_import(action).await,
        #[cfg(feature = "tailscale")]
        Some(Commands::Tailscale { action }) => tailscale_commands::handle_tailscale(action).await,
        Some(Commands::Skills { action }) => handle_skills(action).await,
        Some(Commands::Config { action }) => config_commands::handle_config(action).await,
        Some(Commands::Doctor) => doctor_commands::handle_doctor().await,
        Some(Commands::Hooks { action }) => hooks_commands::handle_hooks(action).await,
        #[cfg(feature = "tls")]
        Some(Commands::TrustCa) => trust_ca().await,
        Some(_) => {
            eprintln!("command not yet implemented");
            Ok(())
        },
    }
}

async fn handle_skills(action: SkillAction) -> anyhow::Result<()> {
    use moltis_skills::{
        discover::FsSkillDiscoverer,
        install,
        registry::{InMemoryRegistry, SkillRegistry},
    };

    let search_paths = FsSkillDiscoverer::default_paths();
    let discoverer = FsSkillDiscoverer::new(search_paths);

    match action {
        SkillAction::List => {
            let registry = InMemoryRegistry::from_discoverer(&discoverer).await?;
            let skills = registry.list_skills().await?;
            if skills.is_empty() {
                println!("No skills found.");
            } else {
                for skill in &skills {
                    let source = skill
                        .source
                        .as_ref()
                        .map(|s| format!("{s:?}"))
                        .unwrap_or_default();
                    println!("  {} — {} [{}]", skill.name, skill.description, source);
                }
            }
        },
        SkillAction::Add { source } => {
            let install_dir = install::default_install_dir()?;
            let skills = install::install_skill(&source, &install_dir).await?;
            for meta in &skills {
                println!("Installed skill '{}': {}", meta.name, meta.description);
            }
        },
        SkillAction::Remove { source } => {
            let install_dir = install::default_install_dir()?;
            install::remove_repo(&source, &install_dir).await?;
            println!("Removed repo '{source}' and all its skills.");
        },
        SkillAction::Info { name } => {
            let registry = InMemoryRegistry::from_discoverer(&discoverer).await?;
            let content = registry.load_skill(&name).await?;
            let meta = &content.metadata;
            println!("Name:        {}", meta.name);
            println!("Description: {}", meta.description);
            if let Some(ref license) = meta.license {
                println!("License:     {license}");
            }
            if !meta.allowed_tools.is_empty() {
                println!("Tools:       {}", meta.allowed_tools.join(", "));
            }
            println!("Path:        {}", meta.path.display());
            println!("Source:      {:?}", meta.source);
            println!("\n{}", content.body);
        },
    }

    Ok(())
}

//! MCP client: manages the protocol handshake and tool interactions with a single MCP server.

use std::{collections::HashMap, sync::Arc};

use tracing::{debug, info, warn};

#[cfg(feature = "metrics")]
use std::time::Instant;

#[cfg(feature = "metrics")]
use moltis_metrics::{counter, gauge, histogram, labels, mcp as mcp_metrics};

use crate::{
    auth::SharedAuthProvider,
    error::{Context, Error, Result},
    sse_transport::SseTransport,
    traits::{McpClientTrait, McpTransport},
    transport::StdioTransport,
    types::{
        ClientCapabilities, ClientInfo, InitializeParams, InitializeResult, McpToolDef,
        PROTOCOL_VERSION, ToolsCallParams, ToolsCallResult, ToolsListResult,
    },
};

/// State of an MCP client connection.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum McpClientState {
    /// Transport spawned, not yet initialized.
    Connected,
    /// `initialize` completed, `initialized` notification sent.
    Ready,
    /// OAuth authentication in progress (waiting for browser).
    Authenticating,
    /// Server process exited or was shut down.
    Closed,
}

/// An MCP client connected to a single server via stdio.
pub struct McpClient {
    server_name: String,
    transport: Arc<dyn McpTransport>,
    state: McpClientState,
    server_info: Option<InitializeResult>,
    tools: Vec<McpToolDef>,
}

impl McpClient {
    /// Spawn the server process and perform the MCP handshake (initialize + initialized).
    pub async fn connect(
        server_name: &str,
        command: &str,
        args: &[String],
        env: &HashMap<String, String>,
    ) -> Result<Self> {
        info!(server = %server_name, command = %command, args = ?args, "connecting to MCP server");
        let transport = StdioTransport::spawn(command, args, env).await?;

        let mut client = Self {
            server_name: server_name.into(),
            transport,
            state: McpClientState::Connected,
            server_info: None,
            tools: Vec::new(),
        };

        if let Err(e) = client.initialize().await {
            warn!(server = %server_name, error = %e, "MCP initialize handshake failed");
            return Err(e);
        }

        // Track MCP server connection
        #[cfg(feature = "metrics")]
        {
            counter!(mcp_metrics::SERVER_CONNECTIONS_TOTAL, labels::SERVER => server_name.to_string())
                .increment(1);
            gauge!(mcp_metrics::SERVERS_CONNECTED).increment(1.0);
        }

        Ok(client)
    }

    /// Connect to a remote MCP server over HTTP/SSE.
    pub async fn connect_sse(server_name: &str, url: &str) -> Result<Self> {
        info!(server = %server_name, url = %url, "connecting to MCP server via SSE");
        let transport = SseTransport::new(url)?;

        let mut client = Self {
            server_name: server_name.into(),
            transport,
            state: McpClientState::Connected,
            server_info: None,
            tools: Vec::new(),
        };

        if let Err(e) = client.initialize().await {
            warn!(server = %server_name, error = %e, "MCP SSE initialize handshake failed");
            return Err(e);
        }
        Ok(client)
    }

    /// Connect to a remote MCP server over HTTP/SSE with an OAuth auth provider.
    pub async fn connect_sse_with_auth(
        server_name: &str,
        url: &str,
        auth: SharedAuthProvider,
    ) -> Result<Self> {
        info!(server = %server_name, url = %url, "connecting to MCP server via SSE (with auth)");
        let transport = SseTransport::with_auth(url, auth)?;

        let mut client = Self {
            server_name: server_name.into(),
            transport,
            state: McpClientState::Connected,
            server_info: None,
            tools: Vec::new(),
        };

        if let Err(e) = client.initialize().await {
            warn!(server = %server_name, error = %e, "MCP SSE (auth) initialize handshake failed");
            return Err(e);
        }

        #[cfg(feature = "metrics")]
        {
            counter!(mcp_metrics::SERVER_CONNECTIONS_TOTAL, labels::SERVER => server_name.to_string())
                .increment(1);
            gauge!(mcp_metrics::SERVERS_CONNECTED).increment(1.0);
        }

        Ok(client)
    }

    async fn initialize(&mut self) -> Result<()> {
        let params = InitializeParams {
            protocol_version: PROTOCOL_VERSION.into(),
            capabilities: ClientCapabilities::default(),
            client_info: ClientInfo {
                name: "moltis".into(),
                version: env!("CARGO_PKG_VERSION").into(),
            },
        };

        let resp = self
            .transport
            .request("initialize", Some(serde_json::to_value(&params)?))
            .await
            .context("MCP initialize request failed")?;

        let result: InitializeResult =
            serde_json::from_value(resp.result.context("MCP initialize returned no result")?)
                .context("failed to parse MCP initialize result")?;

        info!(
            server = %self.server_name,
            protocol = %result.protocol_version,
            server_name = %result.server_info.name,
            "MCP server initialized"
        );

        self.server_info = Some(result);

        // Send `initialized` notification to complete handshake.
        self.transport
            .notify("notifications/initialized", None)
            .await?;
        self.state = McpClientState::Ready;

        Ok(())
    }

    fn ensure_ready(&self) -> Result<()> {
        if self.state != McpClientState::Ready {
            return Err(Error::message(format!(
                "MCP client for '{}' is not ready (state: {:?})",
                self.server_name, self.state
            )));
        }
        Ok(())
    }
}

#[async_trait::async_trait]
impl McpClientTrait for McpClient {
    fn server_name(&self) -> &str {
        &self.server_name
    }

    fn state(&self) -> McpClientState {
        self.state
    }

    fn tools(&self) -> &[McpToolDef] {
        &self.tools
    }

    async fn list_tools(&mut self) -> Result<&[McpToolDef]> {
        self.ensure_ready()?;

        let resp = self.transport.request("tools/list", None).await?;
        let result: ToolsListResult =
            serde_json::from_value(resp.result.context("tools/list returned no result")?)?;

        debug!(
            server = %self.server_name,
            count = result.tools.len(),
            "fetched MCP tools"
        );

        self.tools = result.tools;
        Ok(&self.tools)
    }

    async fn call_tool(&self, name: &str, arguments: serde_json::Value) -> Result<ToolsCallResult> {
        self.ensure_ready()?;

        #[cfg(feature = "metrics")]
        let start = Instant::now();

        let params = ToolsCallParams {
            name: name.into(),
            arguments,
        };

        let result = self
            .transport
            .request("tools/call", Some(serde_json::to_value(&params)?))
            .await;

        match result {
            Ok(resp) => {
                let result: ToolsCallResult =
                    serde_json::from_value(resp.result.context("tools/call returned no result")?)?;

                #[cfg(feature = "metrics")]
                {
                    let duration = start.elapsed().as_secs_f64();

                    counter!(
                        mcp_metrics::TOOL_CALLS_TOTAL,
                        labels::SERVER => self.server_name.clone(),
                        labels::TOOL => name.to_string()
                    )
                    .increment(1);

                    histogram!(
                        mcp_metrics::TOOL_CALL_DURATION_SECONDS,
                        labels::SERVER => self.server_name.clone(),
                        labels::TOOL => name.to_string()
                    )
                    .record(duration);
                }

                Ok(result)
            },
            Err(e) => {
                #[cfg(feature = "metrics")]
                {
                    counter!(
                        mcp_metrics::TOOL_CALL_ERRORS_TOTAL,
                        labels::SERVER => self.server_name.clone(),
                        labels::TOOL => name.to_string()
                    )
                    .increment(1);
                }
                Err(e)
            },
        }
    }

    async fn is_alive(&self) -> bool {
        self.transport.is_alive().await
    }

    async fn shutdown(&mut self) {
        self.state = McpClientState::Closed;
        self.transport.kill().await;

        // Decrement connected servers gauge
        #[cfg(feature = "metrics")]
        {
            gauge!(mcp_metrics::SERVERS_CONNECTED).decrement(1.0);
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_client_state_debug() {
        assert_eq!(format!("{:?}", McpClientState::Connected), "Connected");
