                builder.remove_cached(&full_tag).await
            }
        });

        match result {
            Ok(()) => encode_json(&OkResponse { ok: true }),
            Err(error) => {
                record_error("moltis_sandbox_delete_image", IMAGE_CACHE_DELETE_FAILED);
                encode_error(IMAGE_CACHE_DELETE_FAILED, &error.to_string())
            },
        }
    })
