    with_ffi_boundary(|| {
        emit_log("DEBUG", "bridge", "Loading known providers");
        let providers: Vec<BridgeKnownProvider> = known_providers()
            .into_iter()
            .map(|p| BridgeKnownProvider {
                name: p.name,
                display_name: p.display_name,
                auth_type: p.auth_type.as_str(),
                env_key: p.env_key,
