    }

    #[test]
    fn strips_pre_release_metadata_before_compare() {
        assert!(is_newer_version("v0.3.0-rc.1", "0.2.9"));
        assert!(!is_newer_version("v0.2.5+build.42", "0.2.5"));
    }

    #[test]
    fn builds_update_payload_from_release() {
        let update = update_from_release(
